# memory_leak.py
from memory_profiler import profile

class UnboundedCache:
    def __init__(self):
        self.data = {}  # Never cleaned!

    def add(self, key, value):
        self.data[key] = value

cache = UnboundedCache()

@profile
def process_data():
    for i in range(10000):
        cache.add(i, f"value_{i}")  # Memory grows forever!

process_data()

