from memory_profiler import profile

@profile
def with_list():
    # Creates list then sums (memory-heavy)
    return sum([i ** 2 for i in range(1000000)])

@profile
def with_generator():
    # Generator expression (memory-light)
    return sum(i ** 2 for i in range(1000000))

with_list()
with_generator()

